// com.google.javascript.jscomp.DisambiguatePropertiesTest::testOneType
  public void testOneType() {
    String js = ""
        + " function Foo() {}\n"
        + "Foo.prototype.a = 0;\n"
        + "\n"
        + "var F = new Foo;\n"
        + "F.a = 0;";
